"use strict";parserFactory.register("app.yoru.world",()=>new AppYoruWorldParser);class AppYoruWorldParser extends Parser{constructor(){super()}async getChapterUrls(t){let e=new RegExp("/story/[0-9]+"),r=t.baseURI.match(e)?.[0].slice(7),n=(await HttpClient.fetchJson("https://pxp-main-531j.onrender.com/api/v1/books/"+r)).json,s=n.paywall.first_n_chapters;return n.chapters.map(t=>({sourceUrl:"https://app.yoru.world/en/story/"+r+"/read/"+t.id,title:t.title,isIncludeable:t.number<=s||null==s})).reverse()}async loadEpubMetaInfo(t){let e=new RegExp("/story/[0-9]+"),r=t.baseURI.match(e)?.[0].slice(7),n=(await HttpClient.fetchJson("https://pxp-main-531j.onrender.com/api/v1/books/"+r)).json;this.title=n.title,this.author=n.author.display_name,this.tags=n.tags.map(t=>t.name),this.description=n.summary,this.img=(await HttpClient.fetchJson("https://pxp-main-531j.onrender.com/api/v1/aws/s3/"+n.cover.id+":sign_get")).json}findContent(t){return Parser.findConstrutedContent(t)}extractTitleImpl(){return this.title}extractAuthor(){return this.author}extractSubject(){return this.tags.join(", ")}extractDescription(){return this.description.trim()}findCoverImageUrl(){return this.img}async fetchChapter(t){let e=this.toRestUrl(t),r=(await HttpClient.fetchJson(e)).json,n=(await HttpClient.fetchHtml(r)).responseXML;return this.buildChapter(n,t)}toRestUrl(t){let e=new RegExp("[0-9]+$");return"https://pxp-main-531j.onrender.com/api/v1/book_chapters/"+t.match(e)[0]+"/content"}buildChapter(t,e){let r=Parser.makeEmptyDocForContent(e);return r.content.appendChild(t.body),r.dom}getInformationEpubItemChildNodes(t){return[...t.querySelectorAll("#about-panel.synopsis")]}addTitleToContent(t,e){let r=t.rawDom.createElement("h2");r.innerText=t.title.trim(),e.prepend(r)}}